const company = $('Get Company Report').first().json;
const missionsData = $('Get Missions').first().json;
const brief = $('Get Inbox + Pending').first().json;
const today = new Date().toISOString().split('T')[0];
const weekOf = company.week_of || today;

// Project health section
const healthIcon = h => h === 'GREEN' ? '🟢' : h === 'YELLOW' ? '🟡' : h === 'RED' ? '🔴' : '⚪';
const projectLines = (company.projects || []).map(p =>
  `| ${p.project_code} | ${p.project_name} | ${healthIcon(p.health)} ${p.health} | ${p.schedule_variance_days >= 0 ? '+' : ''}${p.schedule_variance_days}d | $${(p.budget_exposure || 0).toLocaleString()} | ${p.open_risks} risks | ${p.open_decisions} decisions |`
).join('\n');

// Mission status
const missions = missionsData.missions || [];
const inProgress = missions.filter(m => m.status === 'IN_PROGRESS');
const blocked = missions.filter(m => m.status === 'BLOCKED');
const complete = missions.filter(m => m.status === 'COMPLETE');
const missionLines = missions.slice(0, 8).map(m => {
  const icon = m.status === 'IN_PROGRESS' ? '🔵' : m.status === 'BLOCKED' ? '🔴' : m.status === 'COMPLETE' ? '✅' : '⚪';
  const blocker = m.blocker ? ` — ⛔ ${m.blocker}` : '';
  return `- ${icon} **${m.mission_id}**: ${m.title}${blocker}`;
}).join('\n');

// Inbox
const pendingApprovals = brief.inbox_count || 0;
const topItem = brief.one_action ? `\n\n**Next Action:** ${brief.one_action.title}` : '';

const companyHealthIcon = healthIcon(company.company_health);
const riskCount = company.projects_at_risk || 0;

const md = `# HCI Weekly Executive Report
**Week of ${weekOf}** | Generated ${new Date().toISOString().replace('T', ' ').slice(0, 16)}

---

## Company Health: ${companyHealthIcon} ${company.company_health}

| Code | Project | Health | Schedule | Budget Exposure | Risks | Decisions |
|------|---------|--------|----------|-----------------|-------|-----------|
${projectLines || '| — | No projects | — | — | — | — | — |'}

**Portfolio:** ${company.active_projects || 0} active projects | ${riskCount} at risk

---

## AI Mission Status

**${inProgress.length} in progress | ${blocked.length} blocked | ${complete.length} complete**

${missionLines || '_No active missions_'}

---

## Executive Inbox

**${pendingApprovals} item${pendingApprovals !== 1 ? 's' : ''} pending your review**${topItem}

- AI saved **${brief.roi_hours_this_week || 0} hours** this week through automation

---

## Week Summary

${riskCount > 0 ? `⚠️ **${riskCount} project(s) at risk — review required**` : '✅ All projects on track'}
${blocked.length > 0 ? `\n⛔ **${blocked.length} AI mission(s) blocked — Buck action required**` : ''}
${pendingApprovals > 0 ? `\n📥 **${pendingApprovals} approval(s) waiting in Executive Inbox**` : ''}

---
*Generated by AUTO-WEEKLY-EXEC | HCI AI OS*`;

const pushMsg = `${companyHealthIcon} Week of ${weekOf}: ${company.active_projects || 0} projects, ${riskCount} at risk, ${blocked.length} missions blocked, ${pendingApprovals} approvals pending | AI saved ${brief.roi_hours_this_week || 0}h this week`;

return [{ json: {
  md,
  pushMsg,
  company_health: company.company_health,
  projects_at_risk: riskCount,
  missions_blocked: blocked.length,
  pending_approvals: pendingApprovals,
  filename: `reports/weekly/exec-${today}.md`
}}];
